const http = require('http');

const server = http.createServer((req, res) => {
  if (req.url === '/') {
    res.writeHead(200, { 'Content-Type': 'text/html' });
    res.end('<h1>Home Page</h1><p>Welcome to my website!</p>');
  } else if (req.url === '/about') {
    res.writeHead(200, { 'Content-Type': 'text/html' });
    res.end('<h1>About Page</h1><p>This is a Node.js server.</p>');
  } else {
    res.writeHead(404, { 'Content-Type': 'text/html' });
    res.end('<h1>404 - Page Not Found</h1>');
  }
});

server.listen(3000, () => {
  console.log('Server running at http://localhost:3000/');
});
```

**How to run:**
1. Save as `server.js`
2. Run `node server.js`
3. Visit http://localhost:3000/ for home page
4. Visit http://localhost:3000/about for about page
5. Visit any other path to see 404 error

