const fs = require('fs');
const path = require('path');

// Create a sample file first
const sampleContent = 'This is line 1\nThis is line 2\nThis is line 3';
fs.writeFileSync('sample.txt', sampleContent);

// Now read, modify, and write
try {
  const content = fs.readFileSync('sample.txt', 'utf8');
  const modifiedContent = content.toUpperCase();
  fs.writeFileSync('sample-modified.txt', modifiedContent);
  console.log('File successfully modified and saved!');
} catch (error) {
  if (error.code === 'ENOENT') {
    console.error('Error: File not found');
  } else {
    console.error('Error reading/writing file:', error.message);
  }
}

// Async version with better error handling
function modifyFileAsync(inputFile, outputFile) {
  return new Promise((resolve, reject) => {
    fs.readFile(inputFile, 'utf8', (err, content) => {
      if (err) {
        reject(err);
        return;
      }
      const modified = content.toUpperCase();
      fs.writeFile(outputFile, modified, (err) => {
        if (err) {
          reject(err);
          return;
        }
        resolve('File modified successfully');
      });
    });
  });
}

modifyFileAsync('sample.txt', 'sample-async-modified.txt')
  .then(message => console.log(message))
  .catch(err => console.error('Async error:', err.message));
```

```javascript
const http = require('http');
const url = require('url');

// Sample data
const users = [
  { id: 1, name: 'Alice Johnson', email: 'alice@example.com', age: 28 },
  { id: 2, name: 'Bob Smith', email: 'bob@example.com', age: 32 },
  { id: 3, name: 'Charlie Brown', email: 'charlie@example.com', age: 25 }
];

const server = http.createServer((req, res) => {
  const parsedUrl = url.parse(req.url, true);
  const path = parsedUrl.pathname;
  const query = parsedUrl.query;

  // Set CORS headers
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') {
    res.writeHead(204);
    res.end();
    return;
  }

  // GET /api/users - return all users
  if (path === '/api/users' && req.method === 'GET') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ success: true, data: users }));
  }
  // GET /api/users/:id - return specific user
  else if (path.startsWith('/api/users/') && req.method === 'GET') {
    const userId = parseInt(path.split('/')[3]);
    const user = users.find(u => u.id === userId);

    if (user) {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: true, data: user }));
    } else {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: false, error: 'User not found' }));
    }
  }
  // GET /api/users?name=keyword - search users by name
  else if (path === '/api/users' && query.name) {
    const searchTerm = query.name.toLowerCase();
    const filteredUsers = users.filter(user => 
      user.name.toLowerCase().includes(searchTerm)
    );
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ success: true, data: filteredUsers }));
  }
  else {
    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ success: false, error: 'Endpoint not found' }));
  }
});

server.listen(3001, () => {
  console.log('API server running at http://localhost:3001/');
  console.log('Try these endpoints:');
  console.log('  GET http://localhost:3001/api/users');
  console.log('  GET http://localhost:3001/api/users/1');
  console.log('  GET http://localhost:3001/api/users?name=alice');
});
```
